commands.examples:
SELECT * FROM users;
SELECT name, email FROM users WHERE active = true ORDER BY name;
SELECT DISTINCT city FROM users;
SELECT * FROM products ORDER BY price DESC LIMIT 10 OFFSET 20;
SELECT city, COUNT(*) FROM users GROUP BY city HAVING COUNT(*) > 5;

INSERT INTO users (name, email) VALUES ('John', 'john@mail.com');

-- Multiple insert
INSERT INTO users (name, email) VALUES
  ('Alice', 'alice@mail.com'),
  ('Bob', 'bob@mail.com')
RETURNING id, name;

-- Upsert
INSERT INTO users (email, name) VALUES ('john@mail.com', 'John Updated')
ON CONFLICT (email) DO UPDATE SET name = EXCLUDED.name;

-- Insert dari SELECT
INSERT INTO archive SELECT * FROM logs WHERE created_at < '2024-01-01';

UPDATE users SET name = 'Jane' WHERE id = 1;
UPDATE products SET price = price * 1.1 WHERE category = 'electronics';

-- Update dengan FROM (join)
UPDATE orders SET status = 'vip'
FROM users WHERE orders.user_id = users.id AND users.tier = 'premium'
RETURNING orders.*;

DELETE FROM users WHERE id = 1;
DELETE FROM logs WHERE created_at < NOW() - INTERVAL '90 days';

-- Delete dengan USING
DELETE FROM orders USING users
WHERE orders.user_id = users.id AND users.banned = true
RETURNING orders.id;

-- Upsert sederhana
INSERT INTO settings (key, value) VALUES ('theme', 'dark')
ON CONFLICT (key) DO UPDATE SET value = EXCLUDED.value;

-- Do nothing jika sudah ada
INSERT INTO tags (name) VALUES ('postgresql')
ON CONFLICT (name) DO NOTHING;

-- Conditional upsert
INSERT INTO products (sku, price) VALUES ('ABC', 100)
ON CONFLICT (sku) DO UPDATE SET price = EXCLUDED.price
WHERE products.price < EXCLUDED.price;

commands.syntax:
WITH cte_name AS (
  SELECT ...
)
SELECT * FROM cte_name;

commands.examples:
-- CTE sederhana
WITH active_users AS (
  SELECT * FROM users WHERE active = true
)
SELECT * FROM active_users WHERE city = 'Jakarta';

-- CTE rekursif (hierarki)
WITH RECURSIVE tree AS (
  SELECT id, name, parent_id, 1 AS depth FROM categories WHERE parent_id IS NULL
  UNION ALL
  SELECT c.id, c.name, c.parent_id, t.depth + 1
  FROM categories c JOIN tree t ON c.parent_id = t.id
)
SELECT * FROM tree ORDER BY depth;

-- CTE dengan DELETE
WITH deleted AS (
  DELETE FROM logs WHERE created_at < '2024-01-01' RETURNING *
)
INSERT INTO log_archive SELECT * FROM deleted;
